        # Draw star
        pulse_size = self.size * (1 + self.pulse * 0.5)
        gfxdraw.aacircle(surface, int(self.x), int(self.y), int(pulse_size), self.color)
        gfxdraw.filled_circle(surface, int(self.x), int(self.y), int(pulse_size), self.color)


