# Audio generation functions
def generate_sine_wave(frequency, duration, sample_rate):
    """Generate a sine wave for audio"""
    t = np.linspace(0, duration, int(sample_rate * duration), False)
    wave = np.sin(2 * np.pi * frequency * t)
    return wave


def generate_chord(frequencies, duration, sample_rate):
    """Generate a chord from multiple frequencies"""
    wave = np.zeros(int(sample_rate * duration))
    for freq in frequencies:
        wave += generate_sine_wave(freq, duration, sample_rate)
    # Normalize
    wave = wave / np.max(np.abs(wave))
    return wave


def play_note(frequency, duration=0.5):
    """Play a single note"""
    wave = generate_sine_wave(frequency, duration, sample_rate)
    # Convert to int16 for pygame
    audio = (wave * 32767).astype(np.int16)
    # Make stereo
    stereo_audio = np.column_stack([audio, audio])
    sound = pygame.sndarray.make_sound(stereo_audio)
    sound.play()


